    power_up_2: "power_halve",
    power_up_3: "power_swap",
};

export function isFeatureUnlocked(featureKey) {
    // Check if feature locks should be respected
    const respectsLocks = loadRespectsLocks();
    if (!respectsLocks) {
        return true; // All features unlocked
