                this.powerUpCounts.swap.persistent++;
                savePowerUpCounts({
                    hammer: this.powerUpCounts.hammer.persistent,
                    halve: this.powerUpCounts.halve.persistent,
                    swap: this.powerUpCounts.swap.persistent,
