                    // extraMovesDialog.classList.add("hidden");
                    const shopDialog = document.getElementById("shopDialog");
                    if (shopDialog) {
                        shopDialog.classList.remove("hidden");
                        // Update shop coins display
                        this.updateCoinsDisplays();
                    }
                }
            });
